  execute: async (args: { content: string; type: string; context?: string }) => {
    const entry: ReflectionEntry = {
      timestamp: new Date().toISOString(),
      type: args.type as ReflectionEntry["type"],
      content: args.content,
      context: args.context
    };

    try {
