  try {
    const raw = fs.readFileSync(CONFIG_FILE, "utf-8");
    return { ...defaultConfig, ...JSON.parse(raw) };
  } catch (err) {
    console.error(`[CONFIG] Failed to parse ${CONFIG_FILE}: ${err}. Using defaults.`);
